class Solution {
    public List<Integer> findAllPeople(int n, int[][] meetings, int firstPerson) {
        List<Integer> result = new ArrayList<>();
        result.add(0);
        result.add(firstPerson);
        int[][] graph = new int[n][n];
        for (int[] meeting : meetings) {
            graph[meeting[0]][meeting[1]] = Math.min(graph[meeting[0]][meeting[1]], meeting[2]);
            graph[meeting[1]][meeting[0]] = Math.min(graph[meeting[1]][meeting[0]], meeting[2]);
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (graph[i][j] != 0) {
                    result.add(j);
                    graph[i][j] = 0;
                }
            }
        }
        return result;
    }
}
